embed
1、嵌入

对于单个文件，支持嵌入为字符串和byte slice
对于多个文件和文件夹，支持嵌入为新的文件系统Fs
导入embed包，即使无显式使用
go:embed指令用来嵌入，必须紧跟着嵌入后的变量名
只支持嵌入为string，byte slice和embed.FS三种类型，这三种的别名和命名类型都不可以

示例
1）嵌入为字符串
package main

import (
    _ "embed"
    "fmt"
)

//go:embed hello.txt
var s string

func main() {
    fmt.Println(s)
}

2）嵌入为slice
package main

import (
    _ "embed"
    "fmt"
)

//go:embed hello.txt
var b []byte

func main() {
    fmt.Println(b)
}

3）嵌入为fs.FS
嵌入为一个文件
package main

import (
    "embed"
    "fmt"
)

//go:embed hello.txt
var f embed.FS

func main() {
    data, _ := f.ReadFile("hello.txt")
    fmt.Println(string(data))
}

嵌入多个文件
package main

import (
    "embed"
    "fmt"
)

//go:embed hello.txt
//go:embed hello2.txt
var f embed.FS

func main() {
    data, _ := f.ReadFile("hello.txt")
    fmt.Println(string(data))
    data, _ = f.ReadFile("hello2.txt")
    fmt.Println(string(data))
}

嵌入子文件夹下的文件
package main

import (
    "embed"
    "fmt"
)

//go:embed p/hello.txt
//go:embed p/hello2.txt
var f embed.FS

func main() {
    data, _ := f.ReadFile("p/hello.txt")
    fmt.Println(string(data))
    data, _ = f.ReadFile("p/hello2.txt")
    fmt.Println(string(data))
}

4）同一个文件嵌入为多个变量
package main

import (
    _ "embed"
    "fmt"
)

//go:embed hello.txt
var s string

//go:embed hello.txt
var s2 string

func main() {
    fmt.Println(s)

    fmt.Println(s2)
