遍历一个文件下的文件和文件夹信息：
package main

import (
    "embed"
    "fmt"
)

//go:embed *
var f embed.FS

func main() {
    dirEntries, _ := f.ReadDir("p")
    for _, de := range dirEntries {
        fmt.Println(de.Name(), de.IsDir())
    }
}

可以返回子文件夹作为新的文件系统
package main

import (
    "embed"
    "fmt"
    "io/fs"
    "io/ioutil"
)

//go:embed *
var f embed.FS

func main() {
    ps, _ := fs.Sub(f, "p")
    hi, _ := ps.Open("q/hi.txt")
    data, _ := ioutil.ReadAll(hi)
    fmt.Println(string(data))
}

